+export function createDeferredWorld(world: World): DeferredWorld {
+    return {
+        spawn(...traits) {
+            // Reserve an entity id now. It is intentionally invisible until the buffer runs.
+            const entity = createEntity(world);
+            world[$internal].deferredPendingSpawns.add(entity);
+            current(world).commands.push({ type: 'spawn', entity, traits });
+            return entity;
+        },
+        destroy(entity) { current(world).commands.push({ type: 'destroy', entity }); },
+        add(entity, ...traits) { current(world).commands.push({ type: 'add', entity, traits }); },
+        remove(entity, ...traits) { current(world).commands.push({ type: 'remove', entity, traits }); },
+        addExclusive(entity, pair) { current(world).commands.push({ type: 'exclusive', entity, pair }); },
+        flush() { flushDeferred(world, current(world)); },
+    };
+}
+
+export function beginDeferredScope(world: World) {
+    world[$internal].deferredStack.push({ commands: [] });
+}
+
+export function endDeferredScope(world: World) {
+    const buffer = world[$internal].deferredStack.pop()!;
+    flushDeferred(world, buffer);
+}
+
+export function flushPendingForEntity(world: World, entity: Entity) {
+    const ctx = world[$internal];
+    if (ctx.flushingDeferred) return;
+    const buffer = current(world);
+    if (buffer.commands.some((command) => command.entity === entity)) flushDeferred(world, buffer);
+}
+
+export function flushDeferred(world: World, buffer = world[$internal].deferredRoot) {
+    const ctx = world[$internal];
+    if (ctx.flushingDeferred || buffer.commands.length === 0) return;
+    const commands = buffer.commands.splice(0);
+    ctx.flushingDeferred = true;
+    try {
